<script setup>
import { onMounted, ref } from 'vue'
import { createAdminEvent, deleteAdminEvent, getAdminEvents, updateAdminEvent } from '../services/adminApi'
const events = ref([]); const form = ref(null); const error = ref(''); const notice = ref(''); const saving = ref(false)
const empty = () => ({ id: '', titleVi: '', titleEn: '', descriptionVi: '', descriptionEn: '', category: 'main', imageUrl: '', detailImagesText: '', sectionsJson: '[]', startDate: new Date().toISOString().slice(0,10), endDate: new Date().toISOString().slice(0,10) })
const load = async () => { try { events.value = await getAdminEvents() } catch (e) { error.value = e.message } }
const edit = item => { form.value = { ...item, detailImagesText: (item.detailImages || []).join('\n') }; globalThis.scrollTo({ top: 0, behavior: 'smooth' }) }
const create = () => { form.value = empty() }
const payload = () => ({ ...form.value, detailImages: form.value.detailImagesText.split('\n').map(x => x.trim()).filter(Boolean), detailImagesText: undefined })
const save = async () => { saving.value = true; error.value = ''; try { const exists = events.value.some(x => x.id === form.value.id); const result = exists ? await updateAdminEvent(payload()) : await createAdminEvent(payload()); notice.value = `Đã lưu ${result.titleVi}.`; form.value = null; await load() } catch (e) { error.value = e.message } finally { saving.value = false } }
const remove = async item => { if (!globalThis.confirm(`Xóa sự kiện “${item.titleVi}”? Bình luận liên quan cũng sẽ bị xóa.`)) return; try { await deleteAdminEvent(item.id); notice.value = 'Đã xóa sự kiện.'; await load() } catch (e) { error.value = e.message } }
onMounted(load)
</script>
<template><main class="min-h-screen px-4 py-16 sm:px-6 sm:py-24"><div class="mx-auto max-w-7xl"><header class="mb-8 flex items-end justify-between gap-4"><div><p class="text-xs font-black uppercase tracking-[0.24em] text-purple-300">Quản trị</p><h1 class="mt-2 text-4xl font-black text-white">Lịch ra mắt & Sự kiện</h1></div><button class="rounded-xl bg-opm-gold px-5 py-3 text-sm font-black text-black" @click="create">+ Thêm sự kiện</button></header><p v-if="notice" class="mb-4 rounded-xl bg-emerald-500/10 p-3 text-emerald-300">{{ notice }}</p><p v-if="error" class="mb-4 rounded-xl bg-red-500/10 p-3 text-red-300">{{ error }}</p><form v-if="form" class="mb-8 space-y-5 rounded-2xl border border-purple-500/30 bg-[#0b0d13] p-6" @submit.prevent="save"><div class="grid gap-4 md:grid-cols-2 lg:grid-cols-4"><label class="admin-field"><span>ID</span><input v-model="form.id" required maxlength="100" /></label><label class="admin-field"><span>Loại</span><select v-model="form.category"><option>main</option><option>other</option><option>banner</option></select></label><label class="admin-field"><span>Bắt đầu</span><input v-model="form.startDate" type="date" required /></label><label class="admin-field"><span>Kết thúc</span><input v-model="form.endDate" type="date" required /></label><label class="admin-field md:col-span-1 lg:col-span-2"><span>Tiêu đề VI</span><input v-model="form.titleVi" required /></label><label class="admin-field md:col-span-1 lg:col-span-2"><span>Tiêu đề EN</span><input v-model="form.titleEn" required /></label><label class="admin-field md:col-span-2"><span>Mô tả VI</span><textarea v-model="form.descriptionVi" rows="3" /></label><label class="admin-field md:col-span-2"><span>Mô tả EN</span><textarea v-model="form.descriptionEn" rows="3" /></label><label class="admin-field md:col-span-2"><span>Ảnh chính</span><input v-model="form.imageUrl" /></label><label class="admin-field md:col-span-2"><span>Ảnh chi tiết, mỗi dòng một đường dẫn</span><textarea v-model="form.detailImagesText" rows="3" /></label><label class="admin-field md:col-span-2 lg:col-span-4"><span>Sections JSON</span><textarea v-model="form.sectionsJson" rows="5" class="font-mono" /></label></div><div class="flex justify-end gap-3"><button type="button" class="rounded-xl border border-white/10 px-5 py-2 text-white" @click="form = null">Đóng</button><button :disabled="saving" class="rounded-xl bg-opm-gold px-6 py-2 font-black text-black disabled:opacity-50">{{ saving ? 'Đang lưu…' : 'Lưu sự kiện' }}</button></div></form><section class="rounded-2xl border border-white/10 bg-[#0b0d13]"><article v-for="item in events" :key="item.id" class="flex flex-col gap-4 border-b border-white/5 p-5 last:border-0 sm:flex-row sm:items-center"><img :src="item.imageUrl" :alt="item.titleVi" class="h-20 w-28 rounded-xl bg-black/30 object-contain" /><div class="min-w-0 flex-1"><strong class="block truncate text-white">{{ item.titleVi }}</strong><p class="mt-1 text-sm text-gray-500">{{ item.id }} · {{ item.startDate }} → {{ item.endDate }} · {{ item.category }}</p></div><div class="flex gap-2"><button class="rounded-lg border border-white/10 px-3 py-2 text-sm font-bold text-white" @click="edit(item)">Sửa</button><button class="rounded-lg border border-red-500/20 px-3 py-2 text-sm font-bold text-red-300" @click="remove(item)">Xóa</button></div></article><p v-if="events.length === 0" class="p-10 text-center text-gray-500">Chưa có sự kiện.</p></section></div></main></template>
<style scoped>.admin-field span{@apply mb-2 block text-[11px] font-bold uppercase tracking-wider text-gray-400}.admin-field input,.admin-field textarea,.admin-field select{@apply w-full rounded-xl border border-white/10 bg-black/30 px-3 py-2.5 text-sm text-white outline-none transition focus:border-opm-gold}</style>
